// Rich Text Editor
const RichTextEditor = ({ value, onChange }: { value: string, onChange: (html: string) => void }) => {
    const editorRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (editorRef.current && editorRef.current.innerHTML !== value) {
             if (document.activeElement !== editorRef.current) {
                editorRef.current.innerHTML = value;
             }
        }
    }, [value]);

    const execCmd = (command: string, arg: string | undefined = undefined) => {
        document.execCommand('styleWithCSS', false, 'true');
        document.execCommand(command, false, arg);
        if (editorRef.current) onChange(editorRef.current.innerHTML);
    };

    const addLink = () => {
        const url = prompt('Insira a URL do link:');
        if (url) {
            execCmd('createLink', url);
        }
    };

    return (
        <div className="border border-slate-700 dark:border-slate-700 rounded-lg overflow-hidden bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 shadow-sm">
            <div className="flex items-center gap-2 p-2 bg-slate-100 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-700 flex-wrap">
                <div className="flex items-center gap-1 border-r border-slate-300 dark:border-slate-600 pr-2">
                    <button type="button" onMouseDown={(e) => { e.preventDefault(); execCmd('bold'); }} className="p-1.5 hover:bg-slate-200 dark:hover:bg-slate-700 rounded" title="Negrito"><Bold size={16}/></button>
                    <button type="button" onMouseDown={(e) => { e.preventDefault(); execCmd('italic'); }} className="p-1.5 hover:bg-slate-200 dark:hover:bg-slate-700 rounded" title="Itálico"><Italic size={16}/></button>
                </div>
                <div className="flex items-center gap-1 border-r border-slate-300 dark:border-slate-600 pr-2">
                    <button type="button" onMouseDown={(e) => { e.preventDefault(); execCmd('fontSize', '5'); }} className="p-1.5 hover:bg-slate-200 dark:hover:bg-slate-700 rounded" title="Aumentar"><Type size={16}/></button>
                    <button type="button" onMouseDown={(e) => { e.preventDefault(); execCmd('fontSize', '2'); }} className="p-1.5 hover:bg-slate-200 dark:hover:bg-slate-700 rounded" title="Diminuir"><Minus size={16}/></button>
                </div>
                <div className="flex items-center gap-2 border-r border-slate-300 dark:border-slate-600 pr-2">
                    <input type="color" onChange={(e) => execCmd('foreColor', e.target.value)} className="w-6 h-6 border-0 bg-transparent cursor-pointer p-0" defaultValue="#000000" title="Cor do Texto"/>
                    <input type="color" onChange={(e) => execCmd('hiliteColor', e.target.value)} className="w-6 h-6 border-0 bg-transparent cursor-pointer p-0" defaultValue="#ffff00" title="Marca Texto"/>
                </div>
                <div className="flex items-center gap-1 border-r border-slate-300 dark:border-slate-600 pr-2">
                    <button type="button" onMouseDown={(e) => { e.preventDefault(); addLink(); }} className="p-1.5 hover:bg-slate-200 dark:hover:bg-slate-700 rounded" title="Inserir Link"><LinkIcon size={16}/></button>
                </div>
                <button type="button" onMouseDown={(e) => { e.preventDefault(); execCmd('removeFormat'); }} className="p-1.5 hover:bg-red-200 dark:hover:bg-red-900/30 text-red-600 rounded" title="Limpar Formatação"><Eraser size={16}/></button>
            </div>
            <div 
                ref={editorRef}
                className="p-4 min-h-[200px] outline-none prose prose-sm max-w-none dark:prose-invert [&_a]:text-blue-600 [&_a]:underline [&_a]:font-bold bg-white dark:bg-slate-800 text-slate-900 dark:text-slate-100"
