                <div className="p-4 border-t border-slate-200 dark:border-slate-800"><button onClick={onLogout} className="flex items-center gap-2 text-slate-500 hover:text-red-500 w-full px-2 py-2"><LogOut size={16} /> Sair</button></div>
            </aside>
            <main className="flex-1 p-8 ml-64 overflow-y-auto">
                <h1 className="text-3xl font-bold dark:text-white mb-8">Administração</h1>
                {activeTab === 'dashboard' && (
                    <div className="grid grid-cols-2 gap-6">
                        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800"><h3 className="text-slate-500 text-sm font-bold uppercase">Alunos</h3><p className="text-3xl font-bold dark:text-white">{stats.users}</p></div>
                        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800"><h3 className="text-slate-500 text-sm font-bold uppercase">Materiais</h3><p className="text-3xl font-bold dark:text-white">{stats.materials}</p></div>
                    </div>
                )}
                {activeTab === 'message' && (
                    <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 max-w-2xl">
                        <h3 className="text-xl font-bold dark:text-white mb-4">Aviso Geral</h3>
                        <RichTextEditor value={message} onChange={setMessage} />
                        <button onClick={handleSaveMessage} className="mt-4 bg-red-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-red-700">Salvar</button>
                    </div>
                )}
                {activeTab === 'materials' && (
                    <div className="space-y-8">
                        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
                            <h3 className="text-xl font-bold dark:text-white mb-4">Novo Material</h3>
                            <div className="grid grid-cols-2 gap-4 mb-4">
                                <input type="text" placeholder="Título" value={newMatTitle} onChange={e => setNewMatTitle(e.target.value)} className="bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 p-2 rounded text-slate-800 dark:text-white" />
                                <input type="text" placeholder="Matéria" value={newMatSubject} onChange={e => setNewMatSubject(e.target.value)} className="bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 p-2 rounded text-slate-800 dark:text-white" />
                                <input type="text" placeholder="Tópico" value={newMatTopic} onChange={e => setNewMatTopic(e.target.value)} className="bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 p-2 rounded text-slate-800 dark:text-white" />
                                <select value={newMatCategory} onChange={e => setNewMatCategory(e.target.value as any)} className="bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 p-2 rounded text-slate-800 dark:text-white"><option value="GUIDED">Estudo Guiado</option><option value="LEI_SECA">Lei Seca</option></select>
                            </div>
                            <div className="grid grid-cols-3 gap-4 mb-4">
                                <input type="text" placeholder="URL PDF" value={newMatPdf} onChange={e => setNewMatPdf(e.target.value)} className="bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 p-2 rounded text-slate-800 dark:text-white" />
                                <input type="text" placeholder="URL Vídeo" value={newMatVideo} onChange={e => setNewMatVideo(e.target.value)} className="bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 p-2 rounded text-slate-800 dark:text-white" />
                                <input type="text" placeholder="URL Questões" value={newMatQuestions} onChange={e => setNewMatQuestions(e.target.value)} className="bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 p-2 rounded text-slate-800 dark:text-white" />
                            </div>
                            <div className="mb-4"><label className="block text-sm font-bold mb-2 dark:text-slate-300">Conteúdo</label><RichTextEditor value={newMatContent} onChange={setNewMatContent} /></div>
                            <button onClick={handleAddMaterial} className="bg-green-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-green-700">Adicionar</button>
                        </div>
                        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
                            <h3 className="text-xl font-bold dark:text-white mb-4">Materiais Existentes</h3>
                            <div className="space-y-2">{materials.map(m => (<div key={m.id} className="flex justify-between items-center p-3 border border-slate-200 dark:border-slate-700 rounded hover:bg-slate-50 dark:hover:bg-slate-800"><div><span className="font-bold dark:text-white">{m.title}</span><span className="text-xs ml-2 px-2 py-0.5 rounded bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300">{m.category}</span></div><button onClick={() => handleDeleteMaterial(m.id)} className="text-red-500 hover:bg-red-50 p-2 rounded"><Trash2 size={18}/></button></div>))}</div>
                        </div>
                    </div>
                )}
                {activeTab === 'users' && <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800"><h3 className="text-xl font-bold dark:text-white mb-4">Alunos</h3><table className="w-full text-left"><thead><tr className="border-b dark:border-slate-700"><th>Nome</th><th>Email</th><th>Role</th></tr></thead><tbody>{users.map(u => (<tr key={u.id} className="border-b dark:border-slate-800"><td>{u.name}</td><td>{u.email}</td><td>{u.role}</td></tr>))}</tbody></table></div>}
            </main>
        </div>
    );
};

// 3. STUDENT DASHBOARD
const StudentDashboard = ({ user, onLogout, updateProfile, readOnly = false }: { user: User; onLogout: () => void; updateProfile: (u: User) => void; readOnly?: boolean }) => {
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [activeTab, setActiveTab] = useState<'painel' | 'estudo' | 'revisoes' | 'simulados' | 'edital' | 'guiado' | 'leiseca' | 'perfil'>('painel');
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [schedule, setSchedule] = useState<ScheduleItem[]>([]);
  const [goals, setGoals] = useState<DailyGoal[]>([]);
  const [stats, setStats] = useState<QuestionStats>({ total: 0, correct: 0, incorrect: 0, history: [] });
  const [revisions, setRevisions] = useState<RevisionItem[]>([]);
  const [simulados, setSimulados] = useState<Simulado[]>([]);
  const [simuladoResults, setSimuladoResults] = useState<SimuladoResult[]>([]);
  const [studySessions, setStudySessions] = useState<StudySession[]>([]);
  const [materials, setMaterials] = useState<Material[]>([]);
  const [objective, setObjective] = useState(user.objective || '');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [commandMessage, setCommandMessage] = useState('');

  // Revisions Local State
  const [newRevSubject, setNewRevSubject] = useState('');
  const [newRevTopic, setNewRevTopic] = useState('');
  const [newRevDate, setNewRevDate] = useState(getLocalISODate());

  // Edital State
  const [editais, setEditais] = useState<Edital[]>([]);
  const [activeEditalId, setActiveEditalId] = useState<string>('');
  const [editalProgress, setEditalProgress] = useState<EditalProgress[]>([]);

  // Navigation State for Materials
  const [viewState, setViewState] = useState<'SUBJECTS' | 'TOPICS' | 'CONTENT' | 'CONTENT_LIST'>('SUBJECTS');
  const [selectedSubject, setSelectedSubject] = useState<string | null>(null);
  const [selectedTopic, setSelectedTopic] = useState<string | null>(null);
  const [viewMaterial, setViewMaterial] = useState<Material | null>(null);

  const [notifications, setNotifications] = useState<{id: string, message: string, type: 'success' | 'error' | 'info'}[]>([]);
  const showNotification = (message: string, type: 'success' | 'error' | 'info') => {
      const id = Date.now().toString();
      setNotifications(prev => [...prev, { id, message, type }]);
      setTimeout(() => { setNotifications(prev => prev.filter(n => n.id !== id)); }, 3000);
  };

  // Study Room States
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [timerSubject, setTimerSubject] = useState<string>('');
  const [timerSeconds, setTimerSeconds] = useState(0);
  const [quoteIndex, setQuoteIndex] = useState(0);

  // Manual Stats
  const [manualCorrect, setManualCorrect] = useState(0);
  const [manualWrong, setManualWrong] = useState(0);

  // New Goal
  const [newGoalText, setNewGoalText] = useState('');

  const [activeSimulado, setActiveSimulado] = useState<Simulado | null>(null);
  const [simuladoAnswers, setSimuladoAnswers] = useState<Record<number, string>>({});
  const [reviewMode, setReviewMode] = useState(false);
  const [isPracticeMode, setIsPracticeMode] = useState(false); 

  const [statsPeriod, setStatsPeriod] = useState<'DAY' | 'MONTH' | 'YEAR' | 'ALL'>('ALL');

  // Achievement Logic
  const checkAchievements = (newStats: QuestionStats, newTotalHours?: number) => {
      if (readOnly) return;
      const totalQ = newStats.total;
      let totalH = 0;
      if (newTotalHours !== undefined) {
          totalH = newTotalHours;
      } else {
          totalH = subjects.reduce((acc, s) => acc + s.totalHoursStudied, 0);
      }

      const newAchievements = [...user.achievements];
      let unlockedCount = 0;

      ALL_ACHIEVEMENTS_LIST.forEach(ach => {
          const isUnlocked = newAchievements.some(ua => ua.id === ach.id);
          if (isUnlocked) return;

          let achieved = false;
          if (ach.id.startsWith('q_')) {
              const target = parseInt(ach.id.split('_')[1]);
              if (totalQ >= target) achieved = true;
          } else if (ach.id.startsWith('h_')) {
              const target = parseInt(ach.id.split('_')[1]);
              if (totalH >= target) achieved = true;
          }

          if (achieved) {
              newAchievements.push({ ...ach, unlocked: true });
              showNotification(`Conquista Desbloqueada: ${ach.title}`, 'success');
              unlockedCount++;
          }
      });

      if (unlockedCount > 0) {
          const updatedUser = { ...user, achievements: newAchievements };
          updateProfile(updatedUser);
          setStorage('current_user', updatedUser);
          const allUsers = getStorage<User[]>('users', []);
          setStorage('users', allUsers.map(u => u.id === user.id ? updatedUser : u));
      }
  };

  const addRevision = (subject: string, topic: string, date: string) => {
      const intervals = [1, 7, 14, 28];
      const groupId = Date.now().toString();
      const newRevs: RevisionItem[] = intervals.map(days => {
          const d = new Date(date + 'T12:00:00'); 
          d.setDate(d.getDate() + days);
          return {
              id: Math.random().toString(36).substr(2, 9),
              groupId,
              subject,
              topic,
              dateStudied: date,
              scheduledDate: d.toISOString().split('T')[0],
              stage: days as any,
              completed: false
          };
      });
      const updated = [...revisions, ...newRevs];
      setRevisions(updated);
      setStorage(`revisions_${user.id}`, updated);
      showNotification('Ciclo de revisão criado.', 'success');
  };

  const deleteRevisionGroup = (groupId: string, e?: React.MouseEvent) => {
      e?.stopPropagation();
      if(window.confirm("Deseja excluir todo o ciclo de revisão (todos os dias agendados)?")) {
          const updated = revisions.filter(r => r.groupId !== groupId);
          setRevisions(updated);
          setStorage(`revisions_${user.id}`, updated);
          showNotification('Ciclo de revisão removido.', 'info');
      }
  };

  const completeRevision = (id: string) => {
      const updated = revisions.map(r => r.id === id ? { ...r, completed: true } : r);
      setRevisions(updated);
      setStorage(`revisions_${user.id}`, updated);
      showNotification('Revisão concluída!', 'success');
  };

  const handleCreateRevision = () => {
        if(!newRevSubject || !newRevTopic || !newRevDate) {
            showNotification('Preencha todos os campos da revisão', 'error');
            return;
        }
        addRevision(newRevSubject, newRevTopic, newRevDate);
        setNewRevSubject('');
        setNewRevTopic('');
        setNewRevDate(getLocalISODate());
  };

  const saveObjective = () => {
      const updated = { ...user, objective };
      updateProfile(updated);
      setStorage('current_user', updated);
      const allUsers = getStorage<User[]>('users', []);
      setStorage('users', allUsers.map(u => u.id === user.id ? updated : u));
      showNotification('Objetivo salvo!', 'success');
  };

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      try {
          const compressed = await compressImage(file);
          const updated = { ...user, avatar: compressed };
          updateProfile(updated);
          setStorage('current_user', updated);
          const users = getStorage<User[]>('users', []);
          const updatedUsers = users.map(u => u.id === user.id ? updated : u);
          setStorage('users', updatedUsers);
          showNotification('Foto de perfil atualizada!', 'success');
      } catch (error) {
          console.error(error);
          showNotification('Erro ao processar imagem.', 'error');
      }
  };

  // --- Schedule Helpers ---
  const addSubjectToSchedule = (dayIndex: number, subjectName: string) => {
    const dayName = INITIAL_SCHEDULE_DAYS[dayIndex];
    const newSchedule = schedule.map(d => {
        if (d.day === dayName) {
            return { ...d, subjects: [...d.subjects, subjectName] };
        }
        return d;
    });
    setSchedule(newSchedule);
    setStorage('schedule', newSchedule);
  };

  const removeSubjectFromSchedule = (dayIndex: number, subjectIndex: number) => {
    const dayName = INITIAL_SCHEDULE_DAYS[dayIndex];
    const newSchedule = schedule.map(d => {
        if (d.day === dayName) {
            const newSubs = [...d.subjects];
            newSubs.splice(subjectIndex, 1);
            return { ...d, subjects: newSubs };
        }
        return d;
    });
    setSchedule(newSchedule);
    setStorage('schedule', newSchedule);
  };

  // --- Goal Helpers ---
  const addGoal = () => {
    if (!newGoalText) return;
    const goal: DailyGoal = {
        id: Date.now().toString(),
        text: newGoalText,
        completed: false,
        dateCreated: getLocalISODate()
    };
    const updated = [...goals, goal];
    setGoals(updated);
    setStorage('daily_goals', updated);
    setNewGoalText('');
  };

  const toggleGoal = (id: string) => {
    const updated = goals.map(g => g.id === id ? { ...g, completed: !g.completed } : g);
    setGoals(updated);
    setStorage('daily_goals', updated);
  };

  const removeGoal = (id: string) => {
    const updated = goals.filter(g => g.id !== id);
    setGoals(updated);
    setStorage('daily_goals', updated);
  };

  useEffect(() => {
    if (theme === 'dark') document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [theme]);

  useEffect(() => {
    checkDailyReset();
    setSubjects(getStorage<Subject[]>('subjects', []));
    setSchedule(getStorage<ScheduleItem[]>('schedule', INITIAL_SCHEDULE_DAYS.map(day => ({ day, subjects: [] }))));
    setGoals(getStorage<DailyGoal[]>('daily_goals', []));
    setStats(getStorage<QuestionStats>(`stats_${user.id}`, { total: 0, correct: 0, incorrect: 0, history: [] }));
    setRevisions(getStorage<RevisionItem[]>(`revisions_${user.id}`, []));
    setSimulados(getStorage<Simulado[]>('simulados_content', []));
    setSimuladoResults(getStorage<SimuladoResult[]>(`simulado_results_${user.id}`, []));
    setStudySessions(getStorage<StudySession[]>(`study_sessions_${user.id}`, []));
    setMaterials(getStorage<Material[]>('materials_global', []));

    // Edital Loading Logic
    const loadedEditais = getStorage<Edital[]>('all_editais', []);
    const legacyEdital = getStorage<EditalSubject[]>('edital_vertical', []);
    let effectiveEditais = loadedEditais;
    if ((!loadedEditais || loadedEditais.length === 0) && legacyEdital.length > 0) {
        const defaultEdital: Edital = { id: 'default', title: 'Edital Padrão', subjects: legacyEdital };
        effectiveEditais = [defaultEdital];
        setStorage('all_editais', effectiveEditais);
    }
    setEditais(effectiveEditais);
    if (effectiveEditais.length > 0 && !activeEditalId) {
        setActiveEditalId(effectiveEditais[0].id);
    }
    setEditalProgress(getStorage<EditalProgress[]>(`edital_progress_${user.id}`, []));
    setCommandMessage(localStorage.getItem('command_message') || '');
  }, [user.id, user, readOnly]);

  useEffect(() => {
    let interval: any;
    if (isTimerRunning && !readOnly) {
      interval = setInterval(() => { setTimerSeconds(s => s + 1); }, 1000);
    } 
    return () => clearInterval(interval);
  }, [isTimerRunning, readOnly]);

  const handleFinishStudy = () => {
      if (timerSeconds > 0 && timerSubject) {
          const newSession: StudySession = { id: Date.now().toString(), subjectId: timerSubject, durationSeconds: timerSeconds, date: new Date().toISOString() };
          const updatedSessions = [...studySessions, newSession];
          setStudySessions(updatedSessions);
          setStorage(`study_sessions_${user.id}`, updatedSessions);

          const updatedSubjects = subjects.map(s => s.id === timerSubject ? { ...s, totalHoursStudied: s.totalHoursStudied + (timerSeconds / 3600) } : s);
          setSubjects(updatedSubjects);
          setStorage('subjects', updatedSubjects);

          const today = getLocalISODate();
          let newStreak = user.studyStreak || 0;
          if (user.lastStudyDate !== today) {
              const yesterday = new Date(); yesterday.setDate(yesterday.getDate() - 1);
              const yesterdayStr = yesterday.toISOString().split('T')[0];
              if (user.lastStudyDate === yesterdayStr) newStreak++; else newStreak = 1;
              const updatedUser = { ...user, lastStudyDate: today, studyStreak: newStreak };
              updateProfile(updatedUser);
              setStorage('current_user', updatedUser);
          }

          const totalHours = updatedSubjects.reduce((acc, s) => acc + s.totalHoursStudied, 0);
          checkAchievements(stats, totalHours);

          setTimerSeconds(0);
          setIsTimerRunning(false);
          setQuoteIndex(Math.floor(Math.random() * MOTIVATIONAL_QUOTES.length));
          showNotification("Estudo registrado com sucesso! Força e Honra!", "success");
      }
  };

  const updateStats = (correct: number, incorrect: number) => {
      if (readOnly) return;
      const today = getLocalISODate();
      const newHistory = [...(stats.history || [])];
      const todayIdx = newHistory.findIndex(h => h.date === today);
      if (todayIdx >= 0) newHistory[todayIdx].count += (correct + incorrect);
      else newHistory.push({ date: today, count: correct + incorrect });

      const newStats = { total: stats.total + correct + incorrect, correct: stats.correct + correct, incorrect: stats.incorrect + incorrect, history: newHistory };
      setStats(newStats);
      setStorage(`stats_${user.id}`, newStats);
      checkAchievements(newStats);
  };

  const filterByPeriod = (dateStr: string) => {
      if (statsPeriod === 'ALL') return true;
      const date = new Date(dateStr);
      const now = new Date();
      if (statsPeriod === 'DAY') {
          const dDate = new Date(date.getFullYear(), date.getMonth(), date.getDate());
          const dNow = new Date(now.getFullYear(), now.getMonth(), now.getDate());
          return dDate.getTime() === dNow.getTime();
      }
      if (statsPeriod === 'MONTH') return date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
      if (statsPeriod === 'YEAR') return date.getFullYear() === now.getFullYear();
      return true;
  };

  const startSimulado = (sim: Simulado, review = false, previousAnswers?: string, practice = false) => {
      setActiveSimulado(sim); setReviewMode(review); setIsPracticeMode(practice);
      if (review && previousAnswers) {
          const ans: Record<number, string> = {};
          previousAnswers.split(',').forEach(part => {
              const match = part.match(/(\d+)([A-Z])/);
              if (match) ans[parseInt(match[1])] = match[2];
          });
          setSimuladoAnswers(ans);
      } else { setSimuladoAnswers({}); }
  };

  const finishSimulado = () => {
      if(!activeSimulado || reviewMode) return;
      const keyMap = activeSimulado.answerKey.split(',').map(k => k.trim().toUpperCase());
      let correct = 0; let wrong = 0; let answersStringParts = [];
      for(let i=0; i<activeSimulado.questionCount; i++) {
          const qNum = i + 1;
          const userAns = simuladoAnswers[qNum] || 'X';
          const keyItem = keyMap.find(k => k.replace(/[^0-9]/g, '') === qNum.toString()) || keyMap[i];
          const expected = keyItem ? keyItem.replace(/[0-9]/g, '').trim() : '';
          if (userAns === expected) correct++; else wrong++;
          answersStringParts.push(`${qNum}${userAns}`);
      }
      const score = (correct / activeSimulado.questionCount) * 10;
      const res: SimuladoResult = { simuladoId: activeSimulado.id, dateTaken: new Date().toISOString(), correctAnswers: correct, wrongAnswers: wrong, score: score, studentAnswers: answersStringParts.join(',') };
      const newRes = [...simuladoResults, res];
      setSimuladoResults(newRes); setStorage(`simulado_results_${user.id}`, newRes);
      if(!isPracticeMode) { updateStats(correct, wrong); }
      setActiveSimulado(null); showNotification(`Simulado finalizado! Nota: ${score.toFixed(1)}`, 'info');
  };

  const toggleEditalTopic = (topicId: string) => {
      if (readOnly) return;
      let newProgress = [...editalProgress];
      const exists = newProgress.find(p => p.topicId === topicId);
      if(exists) newProgress = newProgress.filter(p => p.topicId !== topicId);
      else newProgress.push({ topicId, completed: true });
      setEditalProgress(newProgress); setStorage(`edital_progress_${user.id}`, newProgress);
  };

  const calculateEditalProgress = () => {
      const active = editais.find(e => e.id === activeEditalId);
      if (!active) return 0;
      let total = 0;
      active.subjects.forEach(s => total += s.topics.length);
      if (total === 0) return 0;
      const activeTopicIds = active.subjects.flatMap(s => s.topics.map(t => t.id));
      const completedCount = editalProgress.filter(p => activeTopicIds.includes(p.topicId)).length;
      return Math.round((completedCount / total) * 100);
  };

  const todaysRevisions = revisions.filter(r => r.scheduledDate === getLocalISODate() && !r.completed);
  const futureRevisions = revisions.filter(r => r.scheduledDate > getLocalISODate() && !r.completed).sort((a,b) => new Date(a.scheduledDate).getTime() - new Date(b.scheduledDate).getTime());

  if (activeSimulado) {
      // Simulado rendering logic (abbreviated for brevity as it was correct in previous version)
      return (
          <div className="min-h-screen bg-slate-100 dark:bg-[#020617] p-4 md:p-8 text-slate-800 dark:text-white">
              <header className="flex justify-between items-center mb-8 border-b border-slate-300 dark:border-slate-800 pb-4 sticky top-0 bg-slate-100 dark:bg-[#020617] z-10">
                  <h1 className="text-xl md:text-2xl font-bold text-red-600">{activeSimulado.title} {reviewMode ? '(GABARITO)' : ''}</h1>
                  <button onClick={() => { setActiveSimulado(null); setReviewMode(false); }} className="text-slate-500 hover:text-red-500">Sair</button>
              </header>
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-150px)]">
                  <div className="bg-white dark:bg-slate-900 rounded-xl overflow-hidden border border-slate-200 dark:border-slate-700 shadow-lg"><iframe src={activeSimulado.pdfUrl} className="w-full h-full" title="Simulado PDF"></iframe></div>
                  <div className="overflow-y-auto bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-700 shadow-lg">
                      <div className="space-y-4">
                          {Array.from({length: activeSimulado.questionCount}).map((_, i) => (
                              <div key={i+1} className="flex gap-2 items-center"><span className="font-bold w-8">{i+1}</span>
                                {['A','B','C','D','E'].slice(0, activeSimulado.type === 'ABCD' ? 4 : (activeSimulado.type === 'CERTO_ERRADO' ? 2 : 5)).map(opt => (
                                    <button key={opt} onClick={() => !reviewMode && setSimuladoAnswers(p => ({...p, [i+1]: opt}))} className={`w-8 h-8 rounded-full border ${simuladoAnswers[i+1] === opt ? 'bg-red-600 text-white border-red-600' : 'border-slate-300 dark:border-slate-600'}`}>{activeSimulado.type === 'CERTO_ERRADO' ? (opt === 'A' ? 'C' : 'E') : opt}</button>
                                ))}
                              </div>
                          ))}
                      </div>
                      {!reviewMode && <button onClick={finishSimulado} className="w-full bg-green-600 text-white font-bold py-3 rounded-xl mt-8">ENVIAR</button>}
                  </div>
              </div>
          </div>
      );
  }

  const filteredSessions = studySessions.filter(s => filterByPeriod(s.date));
  const filteredHistory = (stats.history || []).filter(h => filterByPeriod(h.date));
  const simuladoStats = simuladoResults.sort((a,b) => new Date(a.dateTaken).getTime() - new Date(b.dateTaken).getTime()).map(r => ({ date: simulados.find(s => s.id === r.simuladoId)?.title || 'Sim', value: r.score })).slice(-10);
  const filteredMaterials = materials.filter(m => {
      const matchSubject = m.subject === selectedSubject;
      const matchCategory = m.category === (activeTab === 'guiado' ? 'GUIDED' : 'LEI_SECA');
      if (activeTab === 'leiseca' && viewState === 'CONTENT_LIST') return matchSubject && matchCategory;
      const matchTopic = selectedTopic ? m.topic === selectedTopic : !m.topic;
      return matchSubject && matchCategory && matchTopic;
  });
  const weakestSubjects = [...subjects].sort((a, b) => a.totalHoursStudied - b.totalHoursStudied).slice(0, 3);

  return (
    <div className="flex min-h-screen bg-slate-50 dark:bg-[#020617] text-slate-800 dark:text-slate-200 transition-colors duration-300">
      <ToastContainer notifications={notifications} />
      {!readOnly && (
          <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="md:hidden fixed bottom-6 right-6 z-50 bg-slate-900 text-white p-4 rounded-full shadow-2xl hover:bg-slate-800 transition-transform transform hover:scale-110"><Menu size={24} /></button>
      )}
      {mobileMenuOpen && <div className="fixed inset-0 bg-black/50 z-30 md:hidden backdrop-blur-sm" onClick={() => setMobileMenuOpen(false)}></div>}

      {!readOnly && (
      <aside className={`w-64 bg-white dark:bg-[#0f172a] border-r border-slate-200 dark:border-slate-800 flex flex-col fixed h-full z-40 shadow-lg transition-transform duration-300 ${mobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0`}>
        <div className="p-6 border-b border-slate-200 dark:border-slate-800"><div className="flex items-center gap-2 font-bold text-xl dark:text-white"><img src="https://i.ibb.co/W4vPj3js/MARCADAGUA-1.png" className="w-16 h-auto" alt="Logo" onError={(e) => { (e.target as HTMLImageElement).style.display='none'; }}/><span>SANGUE MILICO</span></div></div>
        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
           {[{ id: 'painel', label: 'Painel Geral', icon: <LayoutDashboard size={18}/> }, { id: 'estudo', label: 'Sala de Estudos', icon: <Clock size={18}/> }, { id: 'guiado', label: 'Estudo Guiado', icon: <BookOpen size={18}/> }, { id: 'leiseca', label: 'Lei Seca', icon: <Scale size={18}/> }, { id: 'revisoes', label: 'Revisões', icon: <Calendar size={18}/> }, { id: 'simulados', label: 'Simulados', icon: <FileText size={18}/> }, { id: 'edital', label: 'Edital Vertical', icon: <CheckSquare size={18}/> }, { id: 'perfil', label: 'Meu Perfil', icon: <UserIcon size={18}/> }].map(item => (
               <button key={item.id} onClick={() => { setActiveTab(item.id as any); setMobileMenuOpen(false); setViewState('SUBJECTS'); setSelectedSubject(null); setSelectedTopic(null); }} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all text-sm font-medium ${activeTab === item.id ? 'bg-red-600 text-white shadow-lg shadow-red-600/20' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}>{item.icon} {item.label}</button>
           ))}
        </nav>
        <div className="p-4 border-t border-slate-200 dark:border-slate-800">
             <button onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="flex items-center gap-2 text-slate-500 hover:text-slate-800 dark:hover:text-white mb-4 px-2 w-full">{theme === 'dark' ? <><Sun size={16}/> Modo Claro</> : <><Moon size={16}/> Modo Escuro</>}</button>
             <button onClick={onLogout} className="flex items-center gap-2 text-slate-500 hover:text-red-500 w-full px-2 py-2 rounded transition"><LogOut size={16} /> Sair</button>
        </div>
      </aside>
      )}

      <main className={`flex-1 p-4 md:p-8 overflow-y-auto ${!readOnly ? 'md:ml-64' : 'w-full'}`}>
        {activeTab === 'painel' && (
            <div className="flex justify-end mb-4"><select value={statsPeriod} onChange={(e) => setStatsPeriod(e.target.value as any)} className="bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-700 text-slate-700 dark:text-slate-300 text-xs rounded px-2 py-1 outline-none"><option value="DAY">Hoje</option><option value="MONTH">Mês Atual</option><option value="YEAR">Este Ano</option><option value="ALL">Todo Período</option></select></div>
        )}

        {activeTab === 'painel' && (
            <div className="space-y-6 animate-fade-in">
                <header><h2 className="text-3xl font-bold dark:text-white mb-1">Bem-vindo, {user.name}</h2><p className="text-slate-500 dark:text-slate-400 italic">"Missão dada é missão cumprida!"</p></header>
                {commandMessage && <div className="bg-[#0f172a] border-l-4 border-red-600 p-6 rounded-lg shadow-sm relative overflow-hidden"><h3 className="text-red-600 font-bold uppercase text-xs tracking-wider mb-2 flex items-center gap-2"><Megaphone size={16}/> MENSAGEM DO COMANDO</h3><div className="prose prose-sm max-w-none text-slate-300" dangerouslySetInnerHTML={{__html: commandMessage}} /></div>}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div className="bg-[#0f172a] border border-slate-800 p-4 rounded-xl shadow-sm hover:border-red-600 transition flex flex-col justify-between h-24"><div className="flex justify-between items-start"><p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Horas Estudadas</p><Clock className="text-red-600" size={18}/></div><h3 className="text-2xl font-bold text-white">{(filteredSessions.reduce((acc,s) => acc+s.durationSeconds,0)/3600).toFixed(1)}h</h3></div>
                    <div className="bg-[#0f172a] border border-slate-800 p-4 rounded-xl shadow-sm hover:border-red-600 transition flex flex-col justify-between h-24"><div className="flex justify-between items-start"><p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Questões Feitas</p><Target className="text-white" size={18}/></div><h3 className="text-2xl font-bold text-white">{filteredHistory.reduce((acc,h) => acc+h.count, 0)}</h3></div>
                    <div className="bg-[#0f172a] border border-slate-800 p-4 rounded-xl shadow-sm hover:border-red-600 transition flex flex-col justify-between h-24"><div className="flex justify-between items-start"><p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Simulados</p><FileText className="text-blue-500" size={18}/></div><h3 className="text-2xl font-bold text-white">{simuladoResults.filter(s => filterByPeriod(s.dateTaken)).length}</h3></div>
                    <div className="bg-[#0f172a] border border-slate-800 p-4 rounded-xl shadow-sm hover:border-red-600 transition flex flex-col justify-between h-24"><div className="flex justify-between items-start"><p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Aproveitamento</p><BarChart2 className="text-green-500" size={18}/></div><h3 className="text-2xl font-bold text-white">{stats.total>0?Math.round((stats.correct/stats.total)*100):0}%</h3></div>
                </div>
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <div className="lg:col-span-2 bg-[#0f172a] border border-slate-800 p-6 rounded-xl"><h3 className="text-lg font-bold text-white mb-4">Evolução de Questões</h3><EvolutionChart data={filteredHistory.map(h => ({ date: h.date, value: h.count }))} /></div>
                    <div className="bg-[#0f172a] border border-slate-800 p-6 rounded-xl"><h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><TrendingUp size={18} className="text-red-500"/> Desempenho Simulados</h3>{simuladoStats.length > 0 ? (<div className="space-y-4">{simuladoResults.slice(-3).reverse().map((res, i) => { const sim = simulados.find(s => s.id === res.simuladoId); return (<div key={i} className="flex justify-between items-center border-b border-slate-800 pb-2 last:border-0"><div><p className="text-sm font-bold text-white line-clamp-1 max-w-[150px]">{sim?.title || 'Simulado'}</p><p className="text-[10px] text-slate-500">{new Date(res.dateTaken).toLocaleDateString()}</p></div><div className="text-right"><span className="text-lg font-bold text-white">{res.score.toFixed(1)}</span><span className="text-[10px] text-slate-500 block">Nota</span></div></div>)})}</div>) : (<p className="text-slate-500 italic text-center py-10 text-sm">Realize simulados.</p>)}</div>
                </div>
                <div className="bg-[#0f172a] border border-slate-800 p-6 rounded-xl"><h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><History size={18}/> Histórico de Estudo</h3><div className="space-y-2">{filteredSessions.slice(-5).reverse().map(session => { const subjName = subjects.find(s => s.id === session.subjectId)?.name || 'Matéria'; return (<div key={session.id} className="flex justify-between items-center bg-[#020617] p-4 rounded border border-slate-800 hover:border-slate-700 transition"><div><p className="font-bold text-white text-sm">{subjName}</p><p className="text-[10px] text-slate-500">{new Date(session.date).toLocaleString()}</p></div><span className="text-red-500 font-mono font-bold text-sm">{formatTime(session.durationSeconds)}</span></div>)})}{filteredSessions.length === 0 && <p className="text-slate-500 italic text-sm">Nenhum registro recente.</p>}</div></div>
            </div>
        )}

        {activeTab === 'estudo' && (
            <div className="space-y-6 animate-fade-in pb-20">
                {/* ROW 1: Schedule & Question Counter */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Cronograma Semanal */}
                    <div className="lg:col-span-2 bg-[#0f172a] rounded-xl border border-slate-800 p-6 flex flex-col">
                        <h3 className="text-xl font-bold text-white mb-6">Cronograma Semanal</h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 overflow-y-auto max-h-[500px] pr-2 custom-scrollbar">
                            {schedule.map((dayItem, dIdx) => (
                                <div key={dayItem.day} className="bg-[#020617] p-4 rounded-lg border border-slate-800">
                                    <h4 className="font-bold text-red-500 mb-3">{dayItem.day}</h4>
                                    <div className="space-y-2 mb-3">
                                        {dayItem.subjects.map((subj, sIdx) => (
                                            <div key={sIdx} className="flex justify-between items-center bg-slate-800 px-3 py-2 rounded text-sm text-slate-200 group">
                                                <span>{subj}</span>
                                                <button onClick={() => removeSubjectFromSchedule(dIdx, sIdx)} className="text-slate-500 hover:text-red-500 opacity-60 group-hover:opacity-100"><XCircle size={14}/></button>
                                            </div>
                                        ))}
                                        {dayItem.subjects.length === 0 && <span className="text-xs text-slate-600 italic">Descanso / Livre</span>}
                                    </div>
                                    <select 
                                        onChange={(e) => { if(e.target.value) { addSubjectToSchedule(dIdx, e.target.value); e.target.value = ""; } }}
                                        className="w-full bg-slate-900 border border-slate-700 text-slate-400 text-xs rounded p-2 outline-none focus:border-red-600"
                                    >
                                        <option value="">+ Adicionar Matéria</option>
                                        {subjects.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                                    </select>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Contador de Questões */}
                    <div className="bg-[#0f172a] rounded-xl border border-slate-800 p-6 flex flex-col">
                        <h3 className="text-xl font-bold text-white mb-6">Contador de Questões</h3>
                        <div className="flex-1 flex flex-col items-center justify-center">
                            <div className="w-48 h-48 relative mb-6">
                                <QuestionPieChart correct={manualCorrect} incorrect={manualWrong} />
                            </div>

                            <div className="w-full grid grid-cols-2 gap-4 mb-6">
                                <div className="bg-[#020617] p-3 rounded-lg border border-green-900/30 flex flex-col items-center">
                                    <span className="text-green-500 font-bold mb-2">Acertos</span>
                                    <div className="flex items-center gap-3">
                                        <button onClick={() => setManualCorrect(Math.max(0, manualCorrect - 1))} className="w-8 h-8 rounded bg-slate-800 text-white flex items-center justify-center hover:bg-slate-700">-</button>
                                        <span className="text-xl font-bold text-white w-8 text-center">{manualCorrect}</span>
                                        <button onClick={() => setManualCorrect(manualCorrect + 1)} className="w-8 h-8 rounded bg-green-600 text-white flex items-center justify-center hover:bg-green-700">+</button>
                                    </div>
                                </div>
                                <div className="bg-[#020617] p-3 rounded-lg border border-red-900/30 flex flex-col items-center">
                                    <span className="text-red-500 font-bold mb-2">Erros</span>
                                    <div className="flex items-center gap-3">
                                        <button onClick={() => setManualWrong(Math.max(0, manualWrong - 1))} className="w-8 h-8 rounded bg-slate-800 text-white flex items-center justify-center hover:bg-slate-700">-</button>
                                        <span className="text-xl font-bold text-white w-8 text-center">{manualWrong}</span>
                                        <button onClick={() => setManualWrong(manualWrong + 1)} className="w-8 h-8 rounded bg-red-600 text-white flex items-center justify-center hover:bg-red-700">+</button>
                                    </div>
                                </div>
                            </div>

                            <button 
                                onClick={() => { updateStats(manualCorrect, manualWrong); setManualCorrect(0); setManualWrong(0); showNotification("Questões registradas!", "success"); }}
                                className="w-full bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-700 font-bold py-3 rounded-lg transition"
                            >
                                Atualizar Contador
                            </button>
                        </div>
                    </div>
                </div>

                {/* ROW 2: Meta do Dia */}
                <div className="bg-[#0f172a] rounded-xl border border-slate-800 p-6">
                    <div className="flex items-center gap-2 mb-4 text-red-500 font-bold text-lg">
                        <CheckSquare /> <h3>Meta do Dia</h3>
                    </div>
                    <div className="space-y-2 mb-4">
                        {goals.map(g => (
                            <div key={g.id} className="flex items-center gap-3 group">
                                <button onClick={() => toggleGoal(g.id)} className={`w-5 h-5 rounded border flex items-center justify-center transition ${g.completed ? 'bg-red-600 border-red-600 text-white' : 'border-slate-600 hover:border-red-500'}`}>
                                    {g.completed && <CheckCircle size={14}/>}
                                </button>
                                <span className={`flex-1 text-sm ${g.completed ? 'text-slate-500 line-through' : 'text-slate-200'}`}>{g.text}</span>
                                <button onClick={() => removeGoal(g.id)} className="text-slate-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition"><Trash2 size={16}/></button>
                            </div>
                        ))}
                        {goals.length === 0 && <p className="text-slate-600 italic text-sm">Nenhuma meta definida para hoje.</p>}
                    </div>
                    <div className="flex gap-2">
                        <input 
                            type="text" 
                            value={newGoalText} 
                            onChange={e => setNewGoalText(e.target.value)} 
                            onKeyDown={e => e.key === 'Enter' && addGoal()}
                            placeholder="Nova meta..." 
                            className="flex-1 bg-[#020617] border border-slate-700 rounded p-2 text-white outline-none focus:border-red-600"
                        />
                        <button onClick={addGoal} className="bg-red-600 text-white px-4 rounded hover:bg-red-700"><Plus/></button>
                    </div>
                </div>

                {/* ROW 3: Cronômetro */}
                <div className="bg-[#020617] rounded-xl border-t-4 border-red-600 p-8 shadow-2xl flex flex-col items-center justify-center relative overflow-hidden">
                    <h3 className="text-slate-500 text-xs font-bold tracking-[0.2em] uppercase mb-4">Cronômetro de Estudo</h3>
                    <div className="text-7xl md:text-8xl font-mono font-bold text-white tracking-widest mb-6">
                        {formatTime(timerSeconds)}
                    </div>
                    <p className="text-yellow-500 italic text-sm md:text-base mb-8 text-center max-w-2xl">
                        "{MOTIVATIONAL_QUOTES[quoteIndex]}"
                    </p>

                    {!isTimerRunning && !timerSeconds ? (
                        <div className="w-full max-w-md mb-6">
                            <select value={timerSubject} onChange={e => setTimerSubject(e.target.value)} className="w-full bg-slate-900 border border-slate-700 text-white p-3 rounded-lg outline-none focus:border-red-600">
                                <option value="">Selecione a matéria para iniciar...</option>
                                {subjects.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>
                        </div>
                    ) : (
                        <div className="mb-6 px-4 py-1 rounded bg-slate-900 text-slate-400 text-xs font-bold uppercase tracking-wider border border-slate-800">
                            {subjects.find(s => s.id === timerSubject)?.name || 'Estudo Livre'}
                        </div>
                    )}

                    <div className="flex gap-4 w-full max-w-lg">
                        {!isTimerRunning ? (
                            <button 
                                onClick={() => { if(!timerSubject) return showNotification("Selecione uma matéria!", "error"); setIsTimerRunning(true); }} 
                                className="flex-1 bg-green-600 hover:bg-green-700 text-white font-bold py-4 rounded-lg flex items-center justify-center gap-2 transition"
                            >
                                <Play size={20}/> INICIAR
                            </button>
                        ) : (
                            <button onClick={() => setIsTimerRunning(false)} className="flex-1 bg-slate-700 hover:bg-slate-600 text-white font-bold py-4 rounded-lg flex items-center justify-center gap-2 transition">
                                <Pause size={20}/> PAUSAR
                            </button>
                        )}

                        <button 
                            onClick={handleFinishStudy} 
                            disabled={timerSeconds === 0}
                            className={`flex-1 font-bold py-4 rounded-lg flex items-center justify-center gap-2 transition ${timerSeconds > 0 ? 'bg-red-900/80 hover:bg-red-800 text-white border border-red-700' : 'bg-slate-900 text-slate-600 cursor-not-allowed'}`}
                        >
                            <StopCircle size={20}/> TERMINAR
                        </button>
                    </div>
                </div>
            </div>
        )}

        {activeTab === 'revisoes' && (
            <div className="space-y-6 animate-fade-in">
                <h2 className="text-2xl font-bold dark:text-white mb-2">Sistema de Revisão Espaçada</h2>
                <div className="bg-white dark:bg-[#0f172a] border border-slate-200 dark:border-slate-800 rounded-xl p-6 shadow-sm"><h3 className="dark:text-white font-bold mb-4">Registrar Novo Estudo</h3><div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end"><div className="col-span-1"><select value={newRevSubject} onChange={e => setNewRevSubject(e.target.value)} className="w-full bg-slate-50 dark:bg-[#020617] border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 rounded-lg px-4 py-3 outline-none focus:border-red-600 transition"><option value="">Matéria</option>{subjects.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}</select></div><div className="col-span-1 md:col-span-2"><input type="text" value={newRevTopic} onChange={e => setNewRevTopic(e.target.value)} placeholder="Assunto (ex: Crase)" className="w-full bg-slate-50 dark:bg-[#020617] border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 rounded-lg px-4 py-3 outline-none focus:border-red-600 transition"/></div><div className="col-span-1 flex gap-2"><input type="date" value={newRevDate} onChange={e => setNewRevDate(e.target.value)} className="w-full bg-slate-50 dark:bg-[#020617] border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 rounded-lg px-4 py-3 outline-none focus:border-red-600 transition"/><button onClick={handleCreateRevision} className="bg-red-600 hover:bg-red-700 text-white font-bold px-6 py-3 rounded-lg transition whitespace-nowrap">Gerar Ciclo</button></div></div></div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="bg-white dark:bg-[#0f172a] border border-slate-200 dark:border-slate-800 rounded-xl p-6 shadow-sm min-h-[200px] flex flex-col"><h3 className="dark:text-white font-bold mb-4 flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-red-500 animate-pulse"/> Revisões de Hoje</h3><div className="flex-1">{todaysRevisions.length > 0 ? (<div className="space-y-3">{todaysRevisions.map(rev => (<div key={rev.id} className="bg-slate-50 dark:bg-[#020617] p-3 rounded border border-slate-200 dark:border-slate-800 flex justify-between items-center group hover:border-red-600 transition"><div><p className="dark:text-white font-bold text-sm">{rev.subject}</p><p className="text-xs text-slate-500">{rev.topic} • {rev.stage} dias</p></div><div className="flex gap-2"><button onClick={(e) => deleteRevisionGroup(rev.groupId, e)} className="text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 p-2 rounded transition"><Trash2 size={18}/></button><button onClick={() => completeRevision(rev.id)} className="text-green-500 hover:bg-green-100 dark:hover:bg-green-900/30 p-2 rounded transition"><CheckCircle size={18}/></button></div></div>))}</div>) : (<div className="h-full flex flex-col items-center justify-center text-slate-400 gap-2"><Calendar size={48} className="opacity-20"/><p className="text-sm italic">Nada para revisar hoje.</p></div>)}</div></div>
                    <div className="bg-white dark:bg-[#0f172a] border border-slate-200 dark:border-slate-800 rounded-xl p-6 shadow-sm min-h-[200px] flex flex-col"><h3 className="dark:text-white font-bold mb-4">Cronograma Futuro</h3><div className="flex-1">{futureRevisions.length > 0 ? (<div className="space-y-3 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">{futureRevisions.map(rev => (<div key={rev.id} className="bg-slate-50 dark:bg-[#020617] p-3 rounded border border-slate-200 dark:border-slate-800 flex justify-between items-center opacity-70 hover:opacity-100 transition"><div><p className="text-slate-600 dark:text-slate-300 font-medium text-sm">{rev.subject}</p><p className="text-xs text-slate-500">{rev.topic} • {rev.stage} dias</p></div><div className="flex items-center gap-3"><span className="text-xs font-bold text-slate-500 bg-slate-200 dark:bg-slate-800 px-2 py-1 rounded">{new Date(rev.scheduledDate).toLocaleDateString('pt-BR', {day:'2-digit', month:'2-digit'})}</span><button onClick={(e) => deleteRevisionGroup(rev.groupId, e)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 p-1.5 rounded transition"><Trash2 size={16}/></button></div></div>))}</div>) : (<div className="h-full flex flex-col items-center justify-center text-slate-400 gap-2"><Calendar size={48} className="opacity-20"/><p className="text-sm italic">Nenhuma revisão futura agendada.</p></div>)}</div></div>
