const App = () => {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const storedUser = getStorage<User | null>('current_user', null);
    if (storedUser) setUser(storedUser);
  }, []);

  const handleLogin = (u: User) => { setUser(u); setStorage('current_user', u); };
  const handleLogout = () => { setUser(null); setStorage('current_user', null); };
  const handleUpdateProfile = (updatedUser: User) => { setUser(updatedUser); setStorage('current_user', updatedUser); };

  if (!user) return <AuthScreen onLogin={handleLogin} />;
  if (user.role === UserRole.ADMIN) return <AdminDashboard user={user} onLogout={handleLogout} />;
  return <StudentDashboard user={user} onLogout={handleLogout} updateProfile={handleUpdateProfile} />;
};

