const formatTime = (secs: number) => {
    const h = Math.floor(secs / 3600);
    const m = Math.floor((secs % 3600) / 60);
    const s = secs % 60;
    return `${h.toString().padStart(2,'0')}:${m.toString().padStart(2,'0')}:${s.toString().padStart(2,'0')}`;
};

const getLocalISODate = () => {
    const d = new Date();
    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
};

const compressImage = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = (event) => {
            const img = new Image();
            img.src = event.target?.result as string;
            img.onload = () => {
                const canvas = document.createElement('canvas');
                const maxWidth = 300; // Resize to max 300px width
                const scaleSize = maxWidth / img.width;
                canvas.width = maxWidth;
                canvas.height = img.height * scaleSize;
                const ctx = canvas.getContext('2d');
                ctx?.drawImage(img, 0, 0, canvas.width, canvas.height);
                // Compress to JPEG 0.7 quality
                resolve(canvas.toDataURL('image/jpeg', 0.7)); 
            };
            img.onerror = (err) => reject(err);
        };
        reader.onerror = (err) => reject(err);
    });
};

// Helper for Themed Icons
const getSubjectIcon = (subjectName: any, className: string = "") => {
    const s = (typeof subjectName === 'string' ? subjectName : "").toLowerCase();
    if (s.includes('direito') || s.includes('legislação') || s.includes('lei') || s.includes('penal') || s.includes('constitucional')) return <Gavel className={className} size={20} />;
    if (s.includes('matemática') || s.includes('raciocínio') || s.includes('exatas') || s.includes('estatística')) return <Calculator className={className} size={20} />;
    if (s.includes('informática') || s.includes('computador') || s.includes('t.i')) return <Cpu className={className} size={20} />;
    if (s.includes('português') || s.includes('língua') || s.includes('literatura')) return <Book className={className} size={20} />;
    if (s.includes('redação') || s.includes('escrita')) return <PenTool className={className} size={20} />;
    if (s.includes('simulado')) return <FileText className={className} size={20} />;
