muladoResults.length > 0 && (<div className="mt-12"><h3 className="font-bold dark:text-white mb-4 text-xl">Histórico de Simulados</h3><div className="bg-white dark:bg-[#0f172a] rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden"><table className="w-full text-left"><thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 text-xs uppercase font-bold"><tr><th className="p-4">Simulado</th><th className="p-4">Data</th><th className="p-4">Nota</th><th className="p-4">Ação</th></tr></thead><tbody className="divide-y divide-slate-100 dark:divide-slate-800">{simuladoResults.slice().reverse().map((res, i) => {const sim = simulados.find(s => s.id === res.simuladoId);return (<tr key={i} className="hover:bg-slate-50 dark:hover:bg-slate-800/50"><td className="p-4 font-medium dark:text-white">{sim?.title || 'Removido'}</td><td className="p-4 text-slate-500 text-sm">{new Date(res.dateTaken).toLocaleDateString()}</td><td className="p-4"><span className={`font-bold ${res.score >= 7 ? 'text-green-500' : 'text-red-500'}`}>{res.score.toFixed(1)}</span></td><td className="p-4">{sim && <button onClick={() => startSimulado(sim, true, res.studentAnswers)} className="text-blue-500 hover:underline text-xs font-bold">Revisar</button>}</td></tr>)})}</tbody></table></div></div>)}</div>
