                            <button onClick={handleAddMaterial} className="bg-green-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-green-700">Adicionar</button>
                        </div>
                        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
                            <h3 className="text-xl font-bold dark:text-white mb-4">Materiais Existentes</h3>
                            <div className="space-y-2">{materials.map(m => (<div key={m.id} className="flex justify-between items-center p-3 border border-slate-200 dark:border-slate-700 rounded hover:bg-slate-50 dark:hover:bg-slate-800"><div><span className="font-bold dark:text-white">{m.title}</span><span className="text-xs ml-2 px-2 py-0.5 rounded bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300">{m.category}</span></div><button onClick={() => handleDeleteMaterial(m.id)} className="text-red-500 hover:bg-red-50 p-2 rounded"><Trash2 size={18}/></button></div>))}</div>
                        </div>
                    </div>
                )}
                {activeTab === 'users' && <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800"><h3 className="text-xl font-bold dark:text-white mb-4">Alunos</h3><table className="w-full text-left"><thead><tr className="border-b dark:border-slate-700"><th>Nome</th><th>Email</th><th>Role</th></tr></thead><tbody>{users.map(u => (<tr key={u.id} className="border-b dark:border-slate-800"><td>{u.name}</td><td>{u.email}</td><td>{u.role}</td></tr>))}</tbody></table></div>}
            </main>
        </div>
    );
};

// 3. STUDENT DASHBOARD
const StudentDashboard = ({ user, onLogout, updateProfile, readOnly = false }: { user: User; onLogout: () => void; updateProfile: (u: User) => void; readOnly?: boolean }) => {
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [activeTab, setActiveTab] = useState<'painel' | 'estudo' | 'revisoes' | 'simulados' | 'edital' | 'guiado' | 'leiseca' | 'perfil'>('painel');
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [schedule, setSchedule] = useState<ScheduleItem[]>([]);
  const [goals, setGoals] = useState<DailyGoal[]>([]);
  const [stats, setStats] = useState<QuestionStats>({ total: 0, correct: 0, incorrect: 0, history: [] });
  const [revisions, setRevisions] = useState<RevisionItem[]>([]);
  const [simulados, setSimulados] = useState<Simulado[]>([]);
  const [simuladoResults, setSimuladoResults] = useState<SimuladoResult[]>([]);
  const [studySessions, setStudySessions] = useState<StudySession[]>([]);
  const [materials, setMaterials] = useState<Material[]>([]);
  const [objective, setObjective] = useState(user.objective || '');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [commandMessage, setCommandMessage] = useState('');

  // Revisions Local State
  const [newRevSubject, setNewRevSubject] = useState('');
  const [newRevTopic, setNewRevTopic] = useState('');
  const [newRevDate, setNewRevDate] = useState(getLocalISODate());

  // Edital State
  const [editais, setEditais] = useState<Edital[]>([]);
  const [activeEditalId, setActiveEditalId] = useState<string>('');
  const [editalProgress, setEditalProgress] = useState<EditalProgress[]>([]);

  // Navigation State for Materials
  const [viewState, setViewState] = useState<'SUBJECTS' | 'TOPICS' | 'CONTENT' | 'CONTENT_LIST'>('SUBJECTS');
  const [selectedSubject, setSelectedSubject] = useState<string | null>(null);
  const [selectedTopic, setSelectedTopic] = useState<string | null>(null);
  const [viewMaterial, setViewMaterial] = useState<Material | null>(null);

  const [notifications, setNotifications] = useState<{id: string, message: string, type: 'success' | 'error' | 'info'}[]>([]);
  const showNotification = (message: string, type: 'success' | 'error' | 'info') => {
      const id = Date.now().toString();
      setNotifications(prev => [...prev, { id, message, type }]);
      setTimeout(() => { setNotifications(prev => prev.filter(n => n.id !== id)); }, 3000);
  };

  // Study Room States
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [timerSubject, setTimerSubject] = useState<string>('');
  const [timerSeconds, setTimerSeconds] = useState(0);
  const [quoteIndex, setQuoteIndex] = useState(0);

  // Manual Stats
  const [manualCorrect, setManualCorrect] = useState(0);
  const [manualWrong, setManualWrong] = useState(0);

  // New Goal
  const [newGoalText, setNewGoalText] = useState('');

  const [activeSimulado, setActiveSimulado] = useState<Simulado | null>(null);
  const [simuladoAnswers, setSimuladoAnswers] = useState<Record<number, string>>({});
  const [reviewMode, setReviewMode] = useState(false);
  const [isPracticeMode, setIsPracticeMode] = useState(false); 

  const [statsPeriod, setStatsPeriod] = useState<'DAY' | 'MONTH' | 'YEAR' | 'ALL'>('ALL');

  // Achievement Logic
  const checkAchievements = (newStats: QuestionStats, newTotalHours?: number) => {
      if (readOnly) return;
      const totalQ = newStats.total;
      let totalH = 0;
      if (newTotalHours !== undefined) {
          totalH = newTotalHours;
      } else {
          totalH = subjects.reduce((acc, s) => acc + s.totalHoursStudied, 0);
      }

      const newAchievements = [...user.achievements];
      let unlockedCount = 0;

      ALL_ACHIEVEMENTS_LIST.forEach(ach => {
          const isUnlocked = newAchievements.some(ua => ua.id === ach.id);
          if (isUnlocked) return;

          let achieved = false;
          if (ach.id.startsWith('q_')) {
              const target = parseInt(ach.id.split('_')[1]);
              if (totalQ >= target) achieved = true;
          } else if (ach.id.startsWith('h_')) {
              const target = parseInt(ach.id.split('_')[1]);
              if (totalH >= target) achieved = true;
          }

          if (achieved) {
              newAchievements.push({ ...ach, unlocked: true });
              showNotification(`Conquista Desbloqueada: ${ach.title}`, 'success');
              unlockedCount++;
          }
      });

      if (unlockedCount > 0) {
          const updatedUser = { ...user, achievements: newAchievements };
          updateProfile(updatedUser);
          setStorage('current_user', updatedUser);
          const allUsers = getStorage<User[]>('users', []);
          setStorage('users', allUsers.map(u => u.id === user.id ? updatedUser : u));
      }
  };

  const addRevision = (subject: string, topic: string, date: string) => {
      const intervals = [1, 7, 14, 28];
      const groupId = Date.now().toString();
      const newRevs: RevisionItem[] = intervals.map(days => {
          const d = new Date(date + 'T12:00:00'); 
          d.setDate(d.getDate() + days);
          return {
              id: Math.random().toString(36).substr(2, 9),
              groupId,
              subject,
              topic,
              dateStudied: date,
              scheduledDate: d.toISOString().split('T')[0],
              stage: days as any,
              completed: false
          };
      });
      const updated = [...revisions, ...newRevs];
      setRevisions(updated);
      setStorage(`revisions_${user.id}`, updated);
      showNotification('Ciclo de revisão criado.', 'success');
  };

  const deleteRevisionGroup = (groupId: string, e?: React.MouseEvent) => {
      e?.stopPropagation();
      if(window.confirm("Deseja excluir todo o ciclo de revisão (todos os dias agendados)?")) {
          const updated = revisions.filter(r => r.groupId !== groupId);
          setRevisions(updated);
          setStorage(`revisions_${user.id}`, updated);
          showNotification('Ciclo de revisão removido.', 'info');
      }
  };

  const completeRevision = (id: string) => {
      const updated = revisions.map(r => r.id === id ? { ...r, completed: true } : r);
      setRevisions(updated);
      setStorage(`revisions_${user.id}`, updated);
      showNotification('Revisão concluída!', 'success');
  };

  const handleCreateRevision = () => {
        if(!newRevSubject || !newRevTopic || !newRevDate) {
            showNotification('Preencha todos os campos da revisão', 'error');
            return;
        }
        addRevision(newRevSubject, newRevTopic, newRevDate);
        setNewRevSubject('');
        setNewRevTopic('');
        setNewRevDate(getLocalISODate());
  };

  const saveObjective = () => {
      const updated = { ...user, objective };
      updateProfile(updated);
      setStorage('current_user', updated);
      const allUsers = getStorage<User[]>('users', []);
      setStorage('users', allUsers.map(u => u.id === user.id ? updated : u));
      showNotification('Objetivo salvo!', 'success');
  };

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      try {
          const compressed = await compressImage(file);
          const updated = { ...user, avatar: compressed };
          updateProfile(updated);
          setStorage('current_user', updated);
          const users = getStorage<User[]>('users', []);
          const updatedUsers = users.map(u => u.id === user.id ? updated : u);
          setStorage('users', updatedUsers);
          showNotification('Foto de perfil atualizada!', 'success');
      } catch (error) {
          console.error(error);
          showNotification('Erro ao processar imagem.', 'error');
      }
  };

  // --- Schedule Helpers ---
  const addSubjectToSchedule = (dayIndex: number, subjectName: string) => {
    const dayName = INITIAL_SCHEDULE_DAYS[dayIndex];
    const newSchedule = schedule.map(d => {
        if (d.day === dayName) {
            return { ...d, subjects: [...d.subjects, subjectName] };
        }
        return d;
    });
    setSchedule(newSchedule);
    setStorage('schedule', newSchedule);
  };

  const removeSubjectFromSchedule = (dayIndex: number, subjectIndex: number) => {
    const dayName = INITIAL_SCHEDULE_DAYS[dayIndex];
    const newSchedule = schedule.map(d => {
        if (d.day === dayName) {
            const newSubs = [...d.subjects];
            newSubs.splice(subjectIndex, 1);
            return { ...d, subjects: newSubs };
        }
        return d;
    });
    setSchedule(newSchedule);
    setStorage('schedule', newSchedule);
  };

  // --- Goal Helpers ---
  const addGoal = () => {
    if (!newGoalText) return;
    const goal: DailyGoal = {
        id: Date.now().toString(),
        text: newGoalText,
        completed: false,
        dateCreated: getLocalISODate()
    };
    const updated = [...goals, goal];
    setGoals(updated);
    setStorage('daily_goals', updated);
    setNewGoalText('');
  };

  const toggleGoal = (id: string) => {
    const updated = goals.map(g => g.id === id ? { ...g, completed: !g.completed } : g);
    setGoals(updated);
    setStorage('daily_goals', updated);
  };

  const removeGoal = (id: string) => {
    const updated = goals.filter(g => g.id !== id);
    setGoals(updated);
    setStorage('daily_goals', updated);
  };

  useEffect(() => {
    if (theme === 'dark') document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [theme]);

  useEffect(() => {
    checkDailyReset();
    setSubjects(getStorage<Subject[]>('subjects', []));
    setSchedule(getStorage<ScheduleItem[]>('schedule', INITIAL_SCHEDULE_DAYS.map(day => ({ day, subjects: [] }))));
    setGoals(getStorage<DailyGoal[]>('daily_goals', []));
    setStats(getStorage<QuestionStats>(`stats_${user.id}`, { total: 0, correct: 0, incorrect: 0, history: [] }));
    setRevisions(getStorage<RevisionItem[]>(`revisions_${user.id}`, []));
    setSimulados(getStorage<Simulado[]>('simulados_content', []));
    setSimuladoResults(getStorage<SimuladoResult[]>(`simulado_results_${user.id}`, []));
    setStudySessions(getStorage<StudySession[]>(`study_sessions_${user.id}`, []));
    setMaterials(getStorage<Material[]>('materials_global', []));

    // Edital Loading Logic
    const loadedEditais = getStorage<Edital[]>('all_editais', []);
    const legacyEdital = getStorage<EditalSubject[]>('edital_vertical', []);
    let effectiveEditais = loadedEditais;
    if ((!loadedEditais || loadedEditais.length === 0) && legacyEdital.length > 0) {
        const defaultEdital: Edital = { id: 'default', title: 'Edital Padrão', subjects: legacyEdital };
        effectiveEditais = [defaultEdital];
        setStorage('all_editais', effectiveEditais);
    }
    setEditais(effectiveEditais);
    if (effectiveEditais.length > 0 && !activeEditalId) {
        setActiveEditalId(effectiveEditais[0].id);
    }
    setEditalProgress(getStorage<EditalProgress[]>(`edital_progress_${user.id}`, []));
    setCommandMessage(localStorage.getItem('command_message') || '');
  }, [user.id, user, readOnly]);

  useEffect(() => {
    let interval: any;
    if (isTimerRunning && !readOnly) {
      interval = setInterval(() => { setTimerSeconds(s => s + 1); }, 1000);
    } 
    return () => clearInterval(interval);
  }, [isTimerRunning, readOnly]);

  const handleFinishStudy = () => {
      if (timerSeconds > 0 && timerSubject) {
          const newSession: StudySession = { id: Date.now().toString(), subjectId: timerSubject, durationSeconds: timerSeconds, date: new Date().toISOString() };
          const updatedSessions = [...studySessions, newSession];
          setStudySessions(updatedSessions);
          setStorage(`study_sessions_${user.id}`, updatedSessions);

          const updatedSubjects = subjects.map(s => s.id === timerSubject ? { ...s, totalHoursStudied: s.totalHoursStudied + (timerSeconds / 3600) } : s);
          setSubjects(updatedSubjects);
          setStorage('subjects', updatedSubjects);

          const today = getLocalISODate();
          let newStreak = user.studyStreak || 0;
          if (user.lastStudyDate !== today) {
              const yesterday = new Date(); yesterday.setDate(yesterday.getDate() - 1);
              const yesterdayStr = yesterday.toISOString().split('T')[0];
              if (user.lastStudyDate === yesterdayStr) newStreak++; else newStreak = 1;
              const updatedUser = { ...user, lastStudyDate: today, studyStreak: newStreak };
              updateProfile(updatedUser);
              setStorage('current_user', updatedUser);
          }

          const totalHours = updatedSubjects.reduce((acc, s) => acc + s.totalHoursStudied, 0);
          checkAchievements(stats, totalHours);

          setTimerSeconds(0);
          setIsTimerRunning(false);
          setQuoteIndex(Math.floor(Math.random() * MOTIVATIONAL_QUOTES.length));
          showNotification("Estudo registrado com sucesso! Força e Honra!", "success");
      }
  };

  const updateStats = (correct: number, incorrect: number) => {
      if (readOnly) return;
      const today = getLocalISODate();
      const newHistory = [...(stats.history || [])];
      const todayIdx = newHistory.findIndex(h => h.date === today);
      if (todayIdx >= 0) newHistory[todayIdx].count += (correct + incorrect);
      else newHistory.push({ date: today, count: correct + incorrect });

      const newStats = { total: stats.total + correct + incorrect, correct: stats.correct + correct, incorrect: stats.incorrect + incorrect, history: newHistory };
      setStats(newStats);
      setStorage(`stats_${user.id}`, newStats);
      checkAchievements(newStats);
  };

  const filterByPeriod = (dateStr: string) => {
      if (statsPeriod === 'ALL') return true;
      const date = new Date(dateStr);
      const now = new Date();
      if (statsPeriod === 'DAY') {
          const dDate = new Date(date.getFullYear(), date.getMonth(), date.getDate());
          const dNow = new Date(now.getFullYear(), now.getMonth(), now.getDate());
          return dDate.getTime() === dNow.getTime();
      }
      if (statsPeriod === 'MONTH') return date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
      if (statsPeriod === 'YEAR') return date.getFullYear() === now.getFullYear();
      return true;
  };

  const startSimulado = (sim: Simulado, review = false, previousAnswers?: string, practice = false) => {
      setActiveSimulado(sim); setReviewMode(review); setIsPracticeMode(practice);
      if (review && previousAnswers) {
          const ans: Record<number, string> = {};
          previousAnswers.split(',').forEach(part => {
              const match = part.match(/(\d+)([A-Z])/);
              if (match) ans[parseInt(match[1])] = match[2];
          });
          setSimuladoAnswers(ans);
      } else { setSimuladoAnswers({}); }
  };

  const finishSimulado = () => {
      if(!activeSimulado || reviewMode) return;
      const keyMap = activeSimulado.answerKey.split(',').map(k => k.trim().toUpperCase());
      let correct = 0; let wrong = 0; let answersStringParts = [];
      for(let i=0; i<activeSimulado.questionCount; i++) {
          const qNum = i + 1;
          const userAns = simuladoAnswers[qNum] || 'X';
          const keyItem = keyMap.find(k => k.replace(/[^0-9]/g, '') === qNum.toString()) || keyMap[i];
          const expected = keyItem ? keyItem.replace(/[0-9]/g, '').trim() : '';
          if (userAns === expected) correct++; else wrong++;
          answersStringParts.push(`${qNum}${userAns}`);
      }
      const score = (correct / activeSimulado.questionCount) * 10;
      const res: SimuladoResult = { simuladoId: activeSimulado.id, dateTaken: new Date().toISOString(), correctAnswers: correct, wrongAnswers: wrong, score: score, studentAnswers: answersStringParts.join(',') };
      const newRes = [...simuladoResults, res];
      setSimuladoResults(newRes); setStorage(`simulado_results_${user.id}`, newRes);
      if(!isPracticeMode) { updateStats(correct, wrong); }
      setActiveSimulado(null); showNotification(`Simulado finalizado! Nota: ${score.toFixed(1)}`, 'info');
  };

  const toggleEditalTopic = (topicId: string) => {
      if (readOnly) return;
      let newProgress = [...editalProgress];
      const exists = newProgress.find(p => p.topicId === topicId);
      if(exists) newProgress = newProgress.filter(p => p.topicId !== topicId);
      else newProgress.push({ topicId, completed: true });
      setEditalProgress(newProgress); setStorage(`edital_progress_${user.id}`, newProgress);
  };

  const calculateEditalProgress = () => {
      const active = editais.find(e => e.id === activeEditalId);
      if (!active) return 0;
      let total = 0;
      active.subjects.forEach(s => total += s.topics.length);
      if (total === 0) return 0;
      const activeTopicIds = active.subjects.flatMap(s => s.topics.map(t => t.id));
      const completedCount = editalProgress.filter(p => activeTopicIds.includes(p.topicId)).length;
      return Math.round((completedCount / total) * 100);
  };

  const todaysRevisions = revisions.filter(r => r.scheduledDate === getLocalISODate() && !r.completed);
  const futureRevisions = revisions.filter(r => r.scheduledDate > getLocalISODate() && !r.completed).sort((a,b) => new Date(a.scheduledDate).getTime() - new Date(b.scheduledDate).getTime());

  if (activeSimulado) {
      return (
          <div className="min-h-screen bg-slate-100 dark:bg-[#020617] p-4 md:p-8 text-slate-800 dark:text-white">
              <header className="flex justify-between items-center mb-8 border-b border-slate-300 dark:border-slate-800 pb-4 sticky top-0 bg-slate-100 dark:bg-[#020617] z-10">
                  <h1 className="text-xl md:text-2xl font-bold text-red-600">{activeSimulado.title} {reviewMode ? '(GABARITO)' : ''}</h1>
                  <button onClick={() => { setActiveSimulado(null); setReviewMode(false); }} className="text-slate-500 hover:text-red-500">Sair</button>
              </header>
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-150px)]">
                  <div className="bg-white dark:bg-slate-900 rounded-xl overflow-hidden border border-slate-200 dark:border-slate-700 shadow-lg"><iframe src={activeSimulado.pdfUrl} className="w-full h-full" title="Simulado PDF"></iframe></div>
                  <div className="overflow-y-auto bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-700 shadow-lg">
                      <div className="space-y-4">
                          {Array.from({length: activeSimulado.questionCount}).map((_, i) => (
                              <div key={i+1} className="flex gap-2 items-center"><span className="font-bold w-8">{i+1}</span>
                                {['A','B','C','D','E'].slice(0, activeSimulado.type === 'ABCD' ? 4 : (activeSimulado.type === 'CERTO_ERRADO' ? 2 : 5)).map(opt => (
                                    <button key={opt} onClick={() => !reviewMode && setSimuladoAnswers(p => ({...p, [i+1]: opt}))} className={`w-8 h-8 rounded-full border ${simuladoAnswers[i+1] === opt ? 'bg-red-600 text-white border-red-600' : 'border-slate-300 dark:border-slate-600'}`}>{activeSimulado.type === 'CERTO_ERRADO' ? (opt === 'A' ? 'C' : 'E') : opt}</button>
                                ))}
                              </div>
                          ))}
                      </div>
                      {!reviewMode && <button onClick={finishSimulado} className="w-full bg-green-600 text-white font-bold py-3 rounded-xl mt-8">ENVIAR</button>}
                  </div>
              </div>
          </div>
      );
  }

  const filteredSessions = studySessions.filter(s => filterByPeriod(s.date));
  const filteredHistory = (stats.history || []).filter(h => filterByPeriod(h.date));
  const simuladoStats = simuladoResults.sort((a,b) => new Date(a.dateTaken).getTime() - new Date(b.dateTaken).getTime()).map(r => ({ date: simulados.find(s => s.id === r.simuladoId)?.title || 'Sim', value: r.score })).slice(-10);
  const filteredMaterials = materials.filter(m => {
      const matchSubject = m.subject === selectedSubject;
      const matchCategory = m.category === (activeTab === 'guiado' ? 'GUIDED' : 'LEI_SECA');
      if (activeTab === 'leiseca' && viewState === 'CONTENT_LIST') return matchSubject && matchCategory;
      const matchTopic = selectedTopic ? m.topic === selectedTopic : !m.topic;
      return matchSubject && matchCategory && matchTopic;
  });
  const weakestSubjects = [...subjects].sort((a, b) => a.totalHoursStudied - b.totalHoursStudied).slice(0, 3);

  const handleMaterialBack = () => {
    if (viewState === 'CONTENT') setViewState('CONTENT_LIST');
    else if (viewState === 'CONTENT_LIST') {
        setViewState(activeTab === 'leiseca' ? 'SUBJECTS' : 'TOPICS'); 
        if(activeTab === 'leiseca') setSelectedSubject(null); else setSelectedTopic(null);
    }
    else if (viewState === 'TOPICS') { setViewState('SUBJECTS'); setSelectedSubject(null); }
  };

  const uniqueSubjects = Array.from(new Set(materials.filter(m => m.category === (activeTab === 'guiado' ? 'GUIDED' : 'LEI_SECA')).map(m => m.subject)));
  const uniqueTopics = selectedSubject ? Array.from(new Set(materials.filter(m => m.subject === selectedSubject && m.category === (activeTab === 'guiado' ? 'GUIDED' : 'LEI_SECA')).map(m => m.topic).filter(t => t))) : [];

  const renderContent = () => {
      switch (activeTab) {
          case 'painel':
              return (
                  <div className="space-y-6 animate-fade-in pb-20 md:pb-0">
                      <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                          <div>
                              <h2 className="text-2xl font-bold">Olá, <span className="text-red-600">{user.name.split(' ')[0]}</span>!</h2>
                              <p className="text-slate-500 italic">"{MOTIVATIONAL_QUOTES[quoteIndex]}"</p>
                          </div>
                          <div className="flex gap-4">
                              <div className="text-center"><div className="text-2xl font-bold flex items-center gap-1 justify-center"><Flame className="text-orange-500" /> {user.studyStreak || 0}</div><div className="text-xs text-slate-500">Dias seguidos</div></div>
                              <div className="text-center"><div className="text-2xl font-bold flex items-center gap-1 justify-center"><Trophy className="text-yellow-500" /> {user.achievements.filter(a => a.unlocked).length}</div><div className="text-xs text-slate-500">Conquistas</div></div>
                          </div>
                      </div>
                      {commandMessage && <div className="bg-yellow-100 dark:bg-yellow-900/20 border-l-4 border-yellow-500 p-4 rounded text-yellow-800 dark:text-yellow-200" dangerouslySetInnerHTML={{__html: commandMessage}}></div>}
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
