                          <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm"><div className="flex justify-between items-start"><div><p className="text-slate-500 text-sm font-bold">Questões</p><h3 className="text-2xl font-bold">{stats.total}</h3></div><div className="p-2 bg-green-100 dark:bg-green-900/30 rounded-lg text-green-600"><CheckCircle size={20}/></div></div></div>
