                      </div>
                      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                          <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm"><h3 className="font-bold mb-4 flex items-center gap-2"><Target size={18}/> Precisão em Questões</h3><QuestionPieChart correct={stats.correct} incorrect={stats.incorrect} /></div>
