                      </div>
                      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                          <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm"><h3 className="font-bold mb-4 flex items-center gap-2"><TrendingUp size={18}/> Evolução de Questões</h3><div className="flex justify-end mb-2 gap-2"><button onClick={() => setStatsPeriod('DAY')} className={`text-xs px-2 py-1 rounded ${statsPeriod === 'DAY' ? 'bg-red-600 text-white' : 'bg-slate-200 dark:bg-slate-700'}`}>Dia</button><button onClick={() => setStatsPeriod('MONTH')} className={`text-xs px-2 py-1 rounded ${statsPeriod === 'MONTH' ? 'bg-red-600 text-white' : 'bg-slate-200 dark:bg-slate-700'}`}>Mês</button></div><EvolutionChart data={filteredHistory} /></div>
