                                  <div className="text-5xl font-mono font-bold tracking-wider">{formatTime(timerSeconds)}</div>
                                  {isTimerRunning && <div className="absolute top-0 right-0 animate-ping w-4 h-4 bg-red-500 rounded-full"></div>}
