                                      <h3 className="font-bold text-lg mb-2">{sim.title}</h3>
                                      <div className="flex justify-between text-sm text-slate-500 mb-4"><span>{sim.questionCount} Questões</span><span>{sim.type}</span></div>
                                      {result && <div className="mb-4 text-sm"><span className="font-bold text-slate-700 dark:text-slate-300">Última nota: </span><span className={result.score >= 7 ? 'text-green-500 font-bold' : 'text-red-500 font-bold'}>{result.score.toFixed(1)}</span></div>}
