                          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                              {uniqueTopics.map(topic => (
                                  <button key={topic} onClick={() => { setSelectedTopic(topic); setViewState('CONTENT_LIST'); }} className="text-left bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 hover:border-red-500 transition flex items-center justify-between group">
                                      <span className="font-medium">{topic || 'Geral'}</span>
                                      <ChevronRight size={16} className="text-slate-400 group-hover:text-red-500"/>
                                  </button>
