                                  <div key={m.id} onClick={() => { setViewMaterial(m); setViewState('CONTENT'); }} className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 hover:border-red-500 cursor-pointer transition">
