                                          {m.videoUrl && <span className="flex items-center gap-1"><Video size={12}/> Vídeo</span>}
                                          {m.questionsUrl && <span className="flex items-center gap-1"><Target size={12}/> Questões</span>}
                                      </div>
                                  </div>
                              ))}
                          </div>
                      </div>
                  );
              }
              if (viewState === 'CONTENT' && viewMaterial) {
                  return (
                      <div className="animate-fade-in h-full flex flex-col pb-20 md:pb-0">
