                                  <h2 className="font-bold text-lg">{viewMaterial.title}</h2>
                                  <div className="flex gap-2">
                                      {viewMaterial.pdfUrl && <a href={viewMaterial.pdfUrl} target="_blank" rel="noreferrer" className="p-2 bg-red-100 text-red-600 rounded hover:bg-red-200" title="Abrir PDF"><FileText size={18}/></a>}
