                                  <label className="text-xs font-bold uppercase text-slate-400 tracking-wider">Objetivo</label>
                                  <div className="flex gap-2 max-w-md mx-auto md:mx-0">
                                      <input type="text" value={objective} onChange={e => setObjective(e.target.value)} disabled={readOnly} className="flex-1 bg-transparent border-b border-slate-300 dark:border-slate-700 focus:border-red-500 outline-none py-1" placeholder="Ex: Passar na PMERJ"/>
                                      {!readOnly && objective !== user.objective && <button onClick={saveObjective} className="text-green-500 hover:text-green-400"><CheckCircle size={20}/></button>}
                                  </div>
                              </div>
                          </div>
                      </div>
                      <div className="bg-white dark:bg-slate-900 p-8 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
                          <h3 className="text-xl font-bold mb-6 flex items-center gap-2"><Award className="text-yellow-500"/> Sala de Troféus</h3>
                          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
                              {ALL_ACHIEVEMENTS_LIST.map(ach => {
                                  const unlocked = user.achievements.some(ua => ua.id === ach.id && ua.unlocked);
                                  return (
                                      <div key={ach.id} className={`p-4 rounded-xl border flex flex-col items-center text-center gap-2 transition ${unlocked ? 'bg-yellow-50 dark:bg-yellow-900/10 border-yellow-200 dark:border-yellow-900/30' : 'bg-slate-50 dark:bg-slate-800/50 border-slate-100 dark:border-slate-800 opacity-50 grayscale'}`}>
                                          <div className="text-3xl">{ach.icon}</div>
                                          <div className="text-xs font-bold leading-tight">{ach.title}</div>
                                          <div className="text-[10px] text-slate-500">{ach.description}</div>
                                      </div>
                                  );
                              })}
                          </div>
                      </div>
                  </div>
              );
          default:
              return null;
      }
  };

  return (
    <div className={`flex min-h-screen bg-slate-50 dark:bg-[#020617] text-slate-800 dark:text-slate-200 font-sans transition-colors duration-300`}>
        <ToastContainer notifications={notifications} />

        {/* Mobile Header */}
        <div className="md:hidden fixed top-0 left-0 w-full bg-white dark:bg-[#0f172a] p-4 flex justify-between items-center z-50 border-b border-slate-200 dark:border-slate-800 shadow-sm">
            <div className="flex items-center gap-2 font-bold text-lg"><ShieldAlert className="text-red-600" size={24}/> <span>SANGUE MILICO</span></div>
            <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="p-2"><Menu size={24}/></button>
        </div>

        {/* Sidebar */}
        <aside className={`fixed md:sticky top-0 h-full z-40 w-72 bg-white dark:bg-[#0f172a] border-r border-slate-200 dark:border-slate-800 flex flex-col transition-transform duration-300 ease-in-out ${mobileMenuOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
            <div className="p-6 border-b border-slate-200 dark:border-slate-800 hidden md:flex items-center gap-3">
                 <img src="https://i.ibb.co/W4vPj3js/MARCADAGUA-1.png" alt="Logo" className="w-10 h-10 object-contain"/>
                 <div><h1 className="font-extrabold tracking-tight text-lg leading-none">SANGUE</h1><h1 className="font-extrabold tracking-tight text-lg leading-none text-red-600">MILICO</h1></div>
            </div>
            <div className="p-4 md:hidden flex justify-end"><button onClick={() => setMobileMenuOpen(false)}><XCircle size={24}/></button></div>
            <nav className="flex-1 overflow-y-auto p-4 space-y-1">
                {[
                    { id: 'painel', label: 'Painel Geral', icon: LayoutDashboard },
                    { id: 'estudo', label: 'Sala de Estudos', icon: Clock },
                    { id: 'guiado', label: 'Estudo Guiado', icon: BookOpen },
                    { id: 'leiseca', label: 'Lei Seca', icon: Scale },
                    { id: 'revisoes', label: 'Revisões', icon: RefreshCw },
                    { id: 'simulados', label: 'Simulados', icon: FileText },
                    { id: 'edital', label: 'Edital Verticalizado', icon: ListIcon },
                    { id: 'perfil', label: 'Meu Perfil', icon: UserIcon },
                ].map(item => (
                    <button key={item.id} onClick={() => { setActiveTab(item.id as any); setMobileMenuOpen(false); setViewState('SUBJECTS'); setSelectedSubject(null); setSelectedTopic(null); setViewMaterial(null); }} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === item.id ? 'bg-red-600 text-white shadow-lg shadow-red-500/30' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}>
                        <item.icon size={20} className={activeTab === item.id ? 'text-white' : 'text-slate-400 group-hover:text-red-500'} />
                        {item.label}
                    </button>
                ))}
            </nav>
            <div className="p-4 border-t border-slate-200 dark:border-slate-800">
                 <button onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition mb-2">
                    {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />} Alternar Tema
                 </button>
                 <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium text-red-500 hover:bg-red-50 dark:hover:bg-red-900/10 transition">
                    <LogOut size={20} /> Sair
                 </button>
            </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 min-w-0 pt-16 md:pt-0 overflow-x-hidden">
            <div className="p-4 md:p-8 max-w-7xl mx-auto">
                {renderContent()}
            </div>
        </main>
    </div>
  );
};

const App = () => {
    const [user, setUser] = useState<User | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const stored = localStorage.getItem('current_user');
        if (stored) {
            setUser(JSON.parse(stored));
        }
        setLoading(false);
    }, []);

    const handleLogin = (u: User) => {
        setUser(u);
        setStorage('current_user', u);
    };

    const handleLogout = () => {
        setUser(null);
        localStorage.removeItem('current_user');
    };

    if (loading) return <div className="flex items-center justify-center min-h-screen bg-slate-900 text-white">Carregando...</div>;

    if (!user) return <AuthScreen onLogin={handleLogin} />;

    if (user.role === UserRole.ADMIN) {
        return <AdminDashboard user={user} onLogout={handleLogout} />;
    }

    return <StudentDashboard user={user} onLogout={handleLogout} updateProfile={handleLogin} />;
};

export default App;
